// Pega o texto do campo "output"
const texto = items[0].json.output;

// Divide o texto pelos parágrafos (duas quebras de linha)
const paragrafos = texto.split(/\n\s*\n/);

// Retorna o array de parágrafos
return [
  {
    json: {
      paragrafos,
    },
  },
];

// Obter a mensagem da query
const message = $json.query || "";

// Extrair número de telefone (procura qualquer número iniciando com 55 e com pelo menos 10 dígitos)
const telefoneMatch = message.match(/(55\d{10,15})/);
const telefone = telefoneMatch ? telefoneMatch[1].trim() : "Telefone não encontrado";

// Extrair a solicitação padronizada (Se existir o texto 'Solicitação:' ou similar)
let solicitacao = "Solicitação não encontrada";

const solicitacaoPadrao = message.match(/Solicitação(?: do cliente)?:\s*(.*?)(?:$|\n|Numero|Número)/i);
if (solicitacaoPadrao) {
    solicitacao = solicitacaoPadrao[1].trim();
} else {
    // Caso não exista o texto padrão, tenta separar utilizando o número encontrado
    if (telefoneMatch) {
        solicitacao = message.replace(telefoneMatch[1], "").trim();
    } else {
        // Última alternativa: pega tudo antes de possíveis quebras
        solicitacao = message.trim();
    }
}

// Retornar os dados extraídos
return {
    solicitacao,
    telefone,
    mensagem_original: message
};

